fun openFileForEditing(file: File) {
    isDataLoading = true
    viewModelScope.launch(Dispatchers.IO) {
        try {
            val content = file.readText()
            withContext(Dispatchers.Main) {
                editingFile = file
                savedStateHandle["editingFilePath"] = file.absolutePath
                _editorText.value = content
                originalText = content
                isEditLocked = true
                recoveryFile?.delete() // Clear old recovery on new file open
                isDataLoading = false
            }
        } catch (e: Exception) {
            withContext(Dispatchers.Main) {
                _editorText.value = "Error reading file: ${e.message}"
